[DataContract]
public final class InventSumUpdateContract extends BusinessEventsContract
{
    private ItemId                  itemId;
    private EcoResItemConfigurationName configId;
    private EcoResItemSizeName      inventSizeId;
    private EcoResItemColorName     inventColorId;
    private EcoResItemStyleName     inventStyleId;
    private InventSiteId            inventSiteId;
    private InventLocationId        inventLocationId;
    private InventBatchId           inventBatchId;
    private WMSLocationId           wMSLocationId;


    private str                     source;
    private str                     transactionType;


    private InventQty               availPhysical;


}

Method.Source:
public static InventSumUpdateContract newFromInventSum(InventSum _inventSum)
{
    InventSumUpdateContract contract = new InventSumUpdateContract();
    InventDim inventDim = InventDim::find(_inventSum.InventDimId);

    contract.parmItemId(_inventSum.ItemId);
    contract.parmConfigId(inventDim.ConfigId);
    contract.parmInventSizeId(inventDim.InventSizeId);
    contract.parmInventColorId(inventDim.InventColorId);
    contract.parmInventStyleId(inventDim.InventStyleId);
    contract.parmInventSiteId(inventDim.InventSiteId);
    contract.parmInventLocationId(inventDim.InventLocationId);
    contract.parmInventBatchId(inventDim.inventBatchId);
    contract.parmWMSLocationId(inventDim.wMSLocationId);

    // Populate the new AvailPhysical field
    contract.parmAvailPhysical(_inventSum.AvailPhysical);

    // Set the new hardcoded values requested
    contract.parmSource('D365');
    contract.parmTransactionType('Inventory Update');

    return contract;
}

